# Generate click sound
def generate_click_sound():
    sample_rate = 44100
    duration = 0.05
    samples = int(sample_rate * duration)
    buf = bytearray(samples * 2)
    for i in range(samples):
        t = i / sample_rate
        val = int(32767 * math.exp(-t * 80) * math.sin(2 * math.pi * 800 * t))
        val = max(-32768, min(32767, val))
        buf[i * 2] = val & 0xFF
        buf[i * 2 + 1] = (val >> 8) & 0xFF
    sound = pygame.sndarray.make_sound(
        pygame.surfarray.make_surface(
            [[0]]
        )
    )
    return None

# Soap bubble class
class SoapBubble:
    def __init__(self):
        self.reset()

    def reset(self):
        self.x = random.randint(0, WIDTH)
        self.y = random.randint(HEIGHT, HEIGHT + 100)
        self.radius = random.randint(8, 25)
        self.speed = random.uniform(0.3, 1.2)
        self.wobble = random.uniform(0, math.pi * 2)
        self.wobble_speed = random.uniform(0.02, 0.05)
        self.alpha = random.randint(40, 100)
        self.hue_offset = random.randint(0, 360)

    def update(self):
        self.y -= self.speed
        self.wobble += self.wobble_speed
        self.x += math.sin(self.wobble) * 0.5
        if self.y < -self.radius * 2:
            self.reset()

    def draw(self, surface):
        if self.radius < 2:
            return
        bubble_surf = pygame.Surface((self.radius * 2 + 4, self.radius * 2 + 4), pygame.SRCALPHA)
        # Main bubble body
        pygame.draw.circle(bubble_surf, (255, 255, 255, self.alpha),
                           (self.radius + 2, self.radius + 2), self.radius)
        # Iridescent shimmer
        t = pygame.time.get_ticks() / 1000.0
        r = int(128 + 127 * math.sin(t + self.hue_offset * 0.017))
        g = int(128 + 127 * math.sin(t + self.hue_offset * 0.017 + 2.094))
        b = int(128 + 127 * math.sin(t + self.hue_offset * 0.017 + 4.189))
        pygame.draw.circle(bubble_surf, (r, g, b, 60),
                           (self.radius + 2, self.radius + 2), self.radius)
        # Highlight
        pygame.draw.circle(bubble_surf, (255, 255, 255, 120),
                           (self.radius - 2, self.radius - 2), self.radius // 3)
        # Outline
        pygame.draw.circle(bubble_surf, (200, 220, 255, 80),
                           (self.radius + 2, self.radius + 2), self.radius, 2)
        surface.blit(bubble_surf, (int(self.x) - self.radius - 2, int(self.y) - self.radius - 2))


# Gold sparkle class
class GoldSparkle:
    def __init__(self, x, y):
        self.x = x + random.randint(-30, 30)
        self.y = y + random.randint(-30, 30)
        self.vx = random.uniform(-2, 2)
        self.vy = random.uniform(-3, -0.5)
        self.life = 1.0
        self.decay = random.uniform(0.02, 0.05)
        self.size = random.randint(2, 5)

    def update(self):
        self.x += self.vx
        self.y += self.vy
        self.vy += 0.05
        self.life -= self.decay
        return self.life > 0

    def draw(self, surface):
        alpha = int(255 * self.life)
        size = max(1, int(self.size * self.life))
        sparkle_surf = pygame.Surface((size * 4, size * 4), pygame.SRCALPHA)
        pygame.draw.circle(sparkle_surf, (255, 215, 0, alpha), (size * 2, size * 2), size)
        surface.blit(sparkle_surf, (int(self.x) - size * 2, int(self.y) - size * 2))


# Ripple class
class Ripple:
    def __init__(self, x, y):
        self.x = x
        self.y = y
        self.radius = 5
        self.max_radius = 80
        self.life = 1.0

    def update(self):
        self.radius += 3
        self.life = 1.0 - (self.radius / self.max_radius)
        return self.radius < self.max_radius

    def draw(self, surface):
        alpha = int(200 * self.life)
        ripple_surf = pygame.Surface((self.radius * 2 + 4, self.radius * 2 + 4), pygame.SRCALPHA)
        pygame.draw.circle(ripple_surf, (0, 212, 255, alpha),
                           (self.radius + 2, self.radius + 2), self.radius, 2)
        surface.blit(ripple_surf, (self.x - self.radius - 2, self.y - self.radius - 2))


