def generate_click_beep():
    """Generate a simple click sound using pygame mixer"""
    sample_rate = 44100
    duration = 0.06
    n_samples = int(sample_rate * duration)
    buf = []
    for i in range(n_samples):
        t = i / sample_rate
        val = int(20000 * math.exp(-t * 60) * math.sin(2 * math.pi * 600 * t))
        val = max(-32768, min(32767, val))
        buf.append(val)
    # Create stereo
    stereo = []
    for v in buf:
        stereo.append(v)
        stereo.append(v)
    import array
    arr = array.array('h', stereo)
    sound = pygame.sndarray.make_sound(
        pygame.sndarray.make_surface if False else None
    )
    return None


def play_click():
    """Play a click sound"""
    try:
        sample_rate = 44100
        duration = 0.06
        n_samples = int(sample_rate * duration)
        import array
        buf = array.array('h')
        for i in range(n_samples):
            t = i / sample_rate
            val = int(20000 * math.exp(-t * 60) * math.sin(2 * math.pi * 600 * t))
            val = max(-32768, min(32767, val))
            buf.append(val)
            buf.append(val)  # stereo
        sound = pygame.sndarray.make_sound(
            pygame.surfarray.map_array(
                pygame.Surface((1, 1)), [[0]]
            )
        )
    except:
        pass


