    print("Starting Auckland's Best Wash Deals application...")
    print(f"Loaded {len(MACHINES)} washing machines")
    print(f"Cheapest deal: {MACHINES[cheapest_idx]['brand']} - ${MACHINES[cheapest_idx]['price']}")

    clock = pygame.time.Clock()

